command.text:
&UnitConversionBeforeSave;
if not exists(select 1 from @@table where ma_vt = $ma_vt.OldValue and dvt = $dvt.OldValue) begin select 'dvt' as field, replace(replace(@$recordHasBeenChanged, '%s1', rtrim($ma_vt.OldValue)), '%s2', rtrim($dvt.OldValue)) as message return end
if @ma_vt <> $ma_vt.OldValue or @dvt <> $dvt.OldValue begin if exists(select 1 from @@table where (not (ma_vt = $ma_vt.OldValue and dvt = $dvt.OldValue)) and ((ma_vt = @ma_vt and dvt = @dvt) or (ma_vt = @ma_vt and dvt like rtrim(@dvt) + '%') or (ma_vt = @ma_vt and rtrim(@dvt) like rtrim(dvt) + '%'))) begin select 'dvt' as field, replace(replace(@$exists, '%s1', rtrim(@ma_vt)), '%s2', rtrim(@dvt)) as message return end if exists(select 1 from ct70 where ma_vt = $ma_vt.OldValue and dvt1 = $dvt.OldValue) begin select 'dvt' as field, replace(replace(@$updateConflict, '%s1', rtrim($ma_vt.OldValue)), '%s2', rtrim($dvt.OldValue)) as message return end if exists(select 1 from ct90 where ma_vt = $ma_vt.OldValue and dvt1 = $dvt.OldValue) begin select 'dvt' as field, replace(replace(@$updateConflict, '%s1', rtrim($ma_vt.OldValue)), '%s2', rtrim($dvt.OldValue)) as message return end end

script.text:
      /* <flatten type="Javascript"> */
function loadItemUOMConversion(f) {
  f.add_onResponseComplete(on$FormLot$ResponseComplete);
  if (f._action  == 'New') f.getItem('ten_hs').value = String.format('({0})', f.getItem('dvt').field.HeaderText);
}
function close$ItemUOMConversion(f) {try {f.remove_onResponseComplete(on$FormLot$ResponseComplete)} catch (ex) {}}
function on$FormLot$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      break;
    case 'GetUnitConversionItemInformation':
      f.getItem('ten_hs').value = String.format('({0})', [result[0].Value);
      break;
    default:
      break;
  }
}
function onChangeUnitConversionItem(o) {
  var f = o.parentForm;
  var c = $func.trim(f.getItem('ma_vt').value);
  if (c == '*') f.getItem('ten_hs').value = '';
    else f.request('GetUnitConversionItemInformation', 'GetUnitConversionItemInformation', ['ma_vt'], o);
}
/* </flatten> */
